import logging
from cement import App, Controller, ex
from cement.utils import shell

class BaseController(Controller):
    class Meta:
        label = 'base'
        description = 'A command-line application for basic arithmetic operations'
        arguments = [
            (['-a', '--add'], {
                'action': 'store_true',
                'help': 'perform addition',
            }),
            (['-s', '--subtract'], {
                'action': 'store_true',
                'help': 'perform subtraction',
            }),
            (['-m', '--multiply'], {
                'action': 'store_true',
                'help': 'perform multiplication',
            }),
            (['-d', '--divide'], {
                'action': 'store_true',
                'help': 'perform division',
            }),
        ]

    def _validate_inputs(self, num1, num2):
        try:
            num1 = float(num1)
            num2 = float(num2)
            return num1, num2
        except ValueError:
            self.app.log.error("Invalid input. Please enter numeric values.")
            return None, None

    def _log_operation(self, operation, num1, num2, result):
        log_msg = f"{operation}: {num1} and {num2} = {result}"
        self.app.log.info(log_msg)

    @ex(help='perform addition')
    def add(self):
        num1 = input("Enter first number: ")
        num2 = input("Enter second number: ")
        num1, num2 = self._validate_inputs(num1, num2)
        if num1 is not None and num2 is not None:
            result = num1 + num2
            print(f"Result: {result}")
            self._log_operation("Addition", num1, num2, result)

    @ex(help='perform subtraction')
    def subtract(self):
        num1 = input("Enter first number: ")
        num2 = input("Enter second number: ")
        num1, num2 = self._validate_inputs(num1, num2)
        if num1 is not None and num2 is not None:
            result = num1 - num2
            print(f"Result: {result}")
            self._log_operation("Subtraction", num1, num2, result)

    @ex(help='perform multiplication')
    def multiply(self):
        num1 = input("Enter first number: ")
        num2 = input("Enter second number: ")
        num1, num2 = self._validate_inputs(num1, num2)
        if num1 is not None and num2 is not None:
            result = num1 * num2
            print(f"Result: {result}")
            self._log_operation("Multiplication", num1, num2, result)

    @ex(help='perform division')
    def divide(self):
        num1 = input("Enter first number: ")
        num2 = input("Enter second number: ")
        num1, num2 = self._validate_inputs(num1, num2)
        if num1 is not None and num2 is not None:
            if num2 == 0:
                self.app.log.error("Division by zero is not allowed.")
            else:
                result = num1 / num2
                print(f"Result: {result}")
                self._log_operation("Division", num1, num2, result)

class ArithmeticApp(App):
    class Meta:
        label = 'arithmetic'
        base_controller = BaseController
        handlers = [BaseController]
        log_handler = 'file'
        log_file = 'arithmetic_operations.log'

def main():
    with ArithmeticApp() as app:
        app.run()

if __name__ == '__main__':
    main()
