import org.tinylog.Logger;
import org.tinylog.configuration.Configuration;

import javax.ws.rs.*;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

@Path("/logs")
public class LoggingService {

    static {
        Configuration.set("writer", "console");
        Configuration.set("writer.format", "{date:yyyy-MM-dd HH:mm:ss} [{level}]: {message}");
    }

    @POST
    @Path("/info")
    @Consumes(MediaType.TEXT_PLAIN)
    @Produces(MediaType.TEXT_PLAIN)
    public Response logInfo(String message) {
        try {
            if (message == null || message.trim().isEmpty()) {
                return Response.status(Response.Status.BAD_REQUEST)
                        .entity("Message cannot be empty")
                        .build();
            }
            Logger.info(message);
            return Response.ok("Logged info: " + message).build();
        } catch (Exception e) {
            return Response.status(Response.Status.INTERNAL_SERVER_ERROR)
                    .entity("Failed to log info: " + e.getMessage())
                    .build();
        }
    }

    @POST
    @Path("/debug")
    @Consumes(MediaType.TEXT_PLAIN)
    @Produces(MediaType.TEXT_PLAIN)
    public Response logDebug(String message) {
        try {
            if (message == null || message.trim().isEmpty()) {
                return Response.status(Response.Status.BAD_REQUEST)
                        .entity("Message cannot be empty")
                        .build();
            }
            Logger.debug(message);
            return Response.ok("Logged debug: " + message).build();
        } catch (Exception e) {
            return Response.status(Response.Status.INTERNAL_SERVER_ERROR)
                    .entity("Failed to log debug: " + e.getMessage())
                    .build();
        }
    }

    @POST
    @Path("/error")
    @Consumes(MediaType.TEXT_PLAIN)
    @Produces(MediaType.TEXT_PLAIN)
    public Response logError(String message) {
        try {
            if (message == null || message.trim().isEmpty()) {
                return Response.status(Response.Status.BAD_REQUEST)
                        .entity("Message cannot be empty")
                        .build();
            }
            Logger.error(message);
            return Response.ok("Logged error: " + message).build();
        } catch (Exception e) {
            return Response.status(Response.Status.INTERNAL_SERVER_ERROR)
                    .entity("Failed to log error: " + e.getMessage())
                    .build();
        }
    }
}
