package com.example.library;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.stub.StreamObserver;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.TimeUnit;

public class LibraryServer {
    private Server server;

    private void start() throws IOException {
        int port = 50051;
        server = ServerBuilder.forPort(port)
                .addService(new LibraryServiceImpl())
                .build()
                .start();
        System.out.println("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.err.println("Shutting down gRPC server");
            try {
                LibraryServer.this.stop();
            } catch (InterruptedException e) {
                e.printStackTrace(System.err);
            }
            System.err.println("Server shut down");
        }));
    }

    private void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        final LibraryServer server = new LibraryServer();
        server.start();
        server.blockUntilShutdown();
    }

    static class LibraryServiceImpl extends LibraryServiceGrpc.LibraryServiceImplBase {
        private final Map<String, Book> books = new HashMap<>();

        @Override
        public void addBook(AddBookRequest request, StreamObserver<AddBookResponse> responseObserver) {
            Book book = request.getBook();
            books.put(book.getId(), book);
            AddBookResponse response = AddBookResponse.newBuilder()
                    .setMessage("Book added successfully")
                    .setBookId(book.getId())
                    .build();
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        }

        @Override
        public void getBook(GetBookRequest request, StreamObserver<GetBookResponse> responseObserver) {
            String bookId = request.getBookId();
            if (!books.containsKey(bookId)) {
                responseObserver.onError(new io.grpc.StatusRuntimeException(io.grpc.Status.NOT_FOUND));
                return;
            }
            Book book = books.get(bookId);
            GetBookResponse response = GetBookResponse.newBuilder()
                    .setBook(book)
                    .build();
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        }

        @Override
        public void deleteBook(DeleteBookRequest request, StreamObserver<DeleteBookResponse> responseObserver) {
            String bookId = request.getBookId();
            if (!books.containsKey(bookId)) {
                responseObserver.onError(new io.grpc.StatusRuntimeException(io.grpc.Status.NOT_FOUND));
                return;
            }
            books.remove(bookId);
            DeleteBookResponse response = DeleteBookResponse.newBuilder()
                    .setMessage("Book deleted successfully")
                    .build();
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        }
    }
}
