package com.example.library;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;

public class LibraryClient {
    private final LibraryServiceGrpc.LibraryServiceBlockingStub blockingStub;

    public LibraryClient(String host, int port) {
        ManagedChannel channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .build();
        blockingStub = LibraryServiceGrpc.newBlockingStub(channel);
    }

    public void addBook(String id, String title, String author) {
        Book book = Book.newBuilder()
                .setId(id)
                .setTitle(title)
                .setAuthor(author)
                .build();
        AddBookRequest request = AddBookRequest.newBuilder()
                .setBook(book)
                .build();
        try {
            AddBookResponse response = blockingStub.addBook(request);
            System.out.println("Added book: " + response.getBookId());
        } catch (StatusRuntimeException e) {
            System.err.println("RPC failed: " + e.getStatus());
        }
    }

    public void getBook(String bookId) {
        GetBookRequest request = GetBookRequest.newBuilder()
                .setBookId(bookId)
                .build();
        try {
            GetBookResponse response = blockingStub.getBook(request);
            System.out.println("Retrieved book: " + response.getBook().getTitle());
        } catch (StatusRuntimeException e) {
            System.err.println("RPC failed: " + e.getStatus());
        }
    }

    public void deleteBook(String bookId) {
        DeleteBookRequest request = DeleteBookRequest.newBuilder()
                .setBookId(bookId)
                .build();
        try {
            DeleteBookResponse response = blockingStub.deleteBook(request);
            System.out.println(response.getMessage());
        } catch (StatusRuntimeException e) {
            System.err.println("RPC failed: " + e.getStatus());
        }
    }

    public static void main(String[] args) {
        LibraryClient client = new LibraryClient("localhost", 50051);
        client.addBook("1", "The Great Gatsby", "F. Scott Fitzgerald");
        client.getBook("1");
        client.deleteBook("1");
    }
}
