#include "CppUTest/TestHarness.h"
#include "CppUTest/CommandLineTestRunner.h"

class Calculator {
public:
    int add(int a, int b) { return a + b; }
    int subtract(int a, int b) { return a - b; }
    int multiply(int a, int b) { return a * b; }
    float divide(int a, int b) {
        if (b == 0) throw std::invalid_argument("Division by zero");
        return static_cast<float>(a) / b;
    }
};

TEST_GROUP(CalculatorTestGroup) {
    Calculator* calculator;

    void setup() override {
        calculator = new Calculator();
    }

    void teardown() override {
        delete calculator;
    }
};

TEST(CalculatorTestGroup, TestAddition) {
    CHECK_EQUAL(5, calculator->add(2, 3));
    CHECK_EQUAL(-1, calculator->add(2, -3));
    CHECK_EQUAL(0, calculator->add(0, 0));
}

TEST(CalculatorTestGroup, TestSubtraction) {
    CHECK_EQUAL(-1, calculator->subtract(2, 3));
    CHECK_EQUAL(5, calculator->subtract(2, -3));
    CHECK_EQUAL(0, calculator->subtract(0, 0));
}

TEST(CalculatorTestGroup, TestMultiplication) {
    CHECK_EQUAL(6, calculator->multiply(2, 3));
    CHECK_EQUAL(-6, calculator->multiply(2, -3));
    CHECK_EQUAL(0, calculator->multiply(0, 5));
}

TEST(CalculatorTestGroup, TestDivision) {
    DOUBLES_EQUAL(2.0, calculator->divide(6, 3), 0.001);
    DOUBLES_EQUAL(-2.0, calculator->divide(6, -3), 0.001);
    CHECK_THROWS(std::invalid_argument, calculator->divide(5, 0));
}

int main(int argc, char** argv) {
    return CommandLineTestRunner::RunAllTests(argc, argv);
}
