use bevy::prelude::*;

fn main() {
    App::build()
        .add_plugins(DefaultPlugins)
        .add_startup_system(setup.system())
        .add_system(handle_window_events.system())
        .add_system(change_color_on_input.system())
        .run();
}

struct Rectangle;
struct RectangleColor(Color);

fn setup(
    mut commands: Commands,
    mut materials: ResMut<Assets<ColorMaterial>>,
) {
    commands.spawn_bundle(OrthographicCameraBundle::new_2d());
    commands
        .spawn_bundle(SpriteBundle {
            material: materials.add(Color::RED.into()),
            sprite: Sprite::new(Vec2::new(100.0, 100.0)),
            ..Default::default()
        })
        .insert(Rectangle)
        .insert(RectangleColor(Color::RED));
}

fn handle_window_events(
    mut windows: ResMut<Windows>,
    mut exit: EventWriter<AppExit>,
    keyboard_input: Res<Input<KeyCode>>,
) {
    let window = windows.get_primary_mut().unwrap();

    if keyboard_input.just_pressed(KeyCode::Escape) {
        exit.send(AppExit);
    }

    if window.is_resized() {
        println!("Window resized to: {}x{}", window.width(), window.height());
    }
}

fn change_color_on_input(
    keyboard_input: Res<Input<KeyCode>>,
    mut query: Query<(&mut Handle<ColorMaterial>, &mut RectangleColor), With<Rectangle>>,
    mut materials: ResMut<Assets<ColorMaterial>>,
) {
    if let Ok((mut material, mut rectangle_color)) = query.single_mut() {
        let mut color_changed = false;
        let mut new_color = rectangle_color.0;

        if keyboard_input.just_pressed(KeyCode::R) {
            new_color = Color::RED;
            color_changed = true;
        } else if keyboard_input.just_pressed(KeyCode::G) {
            new_color = Color::GREEN;
            color_changed = true;
        } else if keyboard_input.just_pressed(KeyCode::B) {
            new_color = Color::BLUE;
            color_changed = true;
        }

        if color_changed {
            rectangle_color.0 = new_color;
            if let Some(mat) = materials.get_mut(&material) {
                mat.color = new_color;
            }
        }
    }
}
