use cot::prelude::*;
use serde::{Deserialize, Serialize};
use std::sync::Mutex;

#[derive(Serialize, Deserialize, Debug)]
struct Item {
    id: u32,
    name: String,
}

#[derive(Default)]
struct AppState {
    items: Mutex<Vec<Item>>,
}

#[derive(Deserialize, Debug)]
struct NewItem {
    name: String,
}

async fn get_items(state: State<AppState>) -> Result<Json<Vec<Item>>, Error> {
    let items = state.items.lock().unwrap();
    Ok(Json(items.clone()))
}

async fn add_item(
    state: State<AppState>,
    Json(new_item): Json<NewItem>,
) -> Result<Json<Item>, Error> {
    if new_item.name.is_empty() {
        return Err(Error::bad_request("Name cannot be empty"));
    }

    let mut items = state.items.lock().unwrap();
    let id = items.len() as u32 + 1;
    let item = Item {
        id,
        name: new_item.name,
    };
    items.push(item.clone());
    Ok(Json(item))
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let app = Router::new()
        .get("/items", get_items)
        .post("/items", add_item)
        .with_state(AppState::default());

    Server::bind("0.0.0.0:8080").serve(app).await?;
    Ok(())
}
