from cornice import Service
from pyramid.config import Configurator
from pyramid.response import Response
import json
from jsonschema import validate, ValidationError

# Sample in-memory database
books_db = []

# JSON Schema for book validation
book_schema = {
    "type": "object",
    "properties": {
        "title": {"type": "string", "minLength": 1},
        "author": {"type": "string", "minLength": 1},
        "isbn": {"type": "string", "minLength": 10},
        "publication_year": {"type": "integer", "minimum": 1000, "maximum": 9999}
    },
    "required": ["title", "author", "isbn"]
}

# Cornice services
books = Service(name='books', path='/books', description="Books collection")
book = Service(name='book', path='/books/{isbn}', description="Individual book")

@books.get()
def get_books(request):
    """Return all books."""
    return Response(content_type='application/json', body=json.dumps(books_db))

@books.post()
def create_book(request):
    """Create a new book."""
    try:
        data = request.json_body
        validate(instance=data, schema=book_schema)

        # Check if ISBN already exists
        if any(b['isbn'] == data['isbn'] for b in books_db):
            return Response(
                content_type='application/json',
                body=json.dumps({"error": "Book with this ISBN already exists"}),
                status=400
            )

        books_db.append(data)
        return Response(
            content_type='application/json',
            body=json.dumps(data),
            status=201
        )
    except ValidationError as e:
        return Response(
            content_type='application/json',
            body=json.dumps({"error": "Invalid data", "details": e.message}),
            status=400
        )
    except Exception as e:
        return Response(
            content_type='application/json',
            body=json.dumps({"error": "Internal server error"}),
            status=500
        )

@book.get()
def get_book(request):
    """Return a specific book by ISBN."""
    isbn = request.matchdict['isbn']
    book = next((b for b in books_db if b['isbn'] == isbn), None)

    if book is None:
        return Response(
            content_type='application/json',
            body=json.dumps({"error": "Book not found"}),
            status=404
        )

    return Response(content_type='application/json', body=json.dumps(book))

@book.put()
def update_book(request):
    """Update a book by ISBN."""
    isbn = request.matchdict['isbn']
    try:
        data = request.json_body
        validate(instance=data, schema=book_schema)

        book_index = next((i for i, b in enumerate(books_db) if b['isbn'] == isbn), None)

        if book_index is None:
            return Response(
                content_type='application/json',
                body=json.dumps({"error": "Book not found"}),
                status=404
            )

        # Ensure ISBN in URL matches payload
        if data.get('isbn') != isbn:
            return Response(
                content_type='application/json',
                body=json.dumps({"error": "ISBN in URL does not match payload"}),
                status=400
            )

        books_db[book_index] = data
        return Response(content_type='application/json', body=json.dumps(data))

    except ValidationError as e:
        return Response(
            content_type='application/json',
            body=json.dumps({"error": "Invalid data", "details": e.message}),
            status=400
        )
    except Exception as e:
        return Response(
            content_type='application/json',
            body=json.dumps({"error": "Internal server error"}),
            status=500
        )

@book.delete()
def delete_book(request):
    """Delete a book by ISBN."""
    isbn = request.matchdict['isbn']
    book_index = next((i for i, b in enumerate(books_db) if b['isbn'] == isbn), None)

    if book_index is None:
        return Response(
            content_type='application/json',
            body=json.dumps({"error": "Book not found"}),
            status=404
        )

    del books_db[book_index]
    return Response(
        content_type='application/json',
        body=json.dumps({"message": "Book deleted successfully"}),
        status=200
    )

def includeme(config):
    config.include("cornice")
    config.scan()

if __name__ == '__main__':
    config = Configurator()
    config.include(includeme)
    app = config.make_wsgi_app()
    from wsgiref.simple_server import make_server
    server = make_server('0.0.0.0', 6543, app)
    server.serve_forever()
