use cot::prelude::*;
use serde::{Deserialize, Serialize};
use sqlx::{sqlite::SqlitePool, Sqlite};
use validator::Validate;

#[derive(Debug, Serialize, Deserialize, Validate)]
struct Note {
    id: Option<i64>,
    #[validate(length(min = 1, max = 100))]
    title: String,
    #[validate(length(min = 1))]
    content: String,
}

#[derive(Debug, Serialize)]
struct ApiResponse<T> {
    success: bool,
    data: Option<T>,
    error: Option<String>,
}

#[cot::main]
async fn main() -> Result<(), sqlx::Error> {
    let pool = SqlitePool::connect("sqlite:notes.db").await?;

    sqlx::query(
        r#"
        CREATE TABLE IF NOT EXISTS notes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL,
            content TEXT NOT NULL
        )
        "#,
    )
    .execute(&pool)
    .await?;

    let app = cot::router()
        .route("/notes", get(get_notes).post(create_note))
        .route(
            "/notes/:id",
            get(get_note)
                .put(update_note)
                .delete(delete_note),
        )
        .with_state(pool);

    cot::serve(app).await?;
    Ok(())
}

async fn get_notes(State(pool): State<SqlitePool>) -> Json<ApiResponse<Vec<Note>>> {
    match sqlx::query_as::<_, Note>("SELECT id, title, content FROM notes")
        .fetch_all(&pool)
        .await
    {
        Ok(notes) => Json(ApiResponse {
            success: true,
            data: Some(notes),
            error: None,
        }),
        Err(e) => Json(ApiResponse {
            success: false,
            data: None,
            error: Some(format!("Failed to fetch notes: {}", e)),
        }),
    }
}

async fn get_note(
    Path(id): Path<i64>,
    State(pool): State<SqlitePool>,
) -> Json<ApiResponse<Note>> {
    match sqlx::query_as::<_, Note>("SELECT id, title, content FROM notes WHERE id = ?")
        .bind(id)
        .fetch_one(&pool)
        .await
    {
        Ok(note) => Json(ApiResponse {
            success: true,
            data: Some(note),
            error: None,
        }),
        Err(e) => Json(ApiResponse {
            success: false,
            data: None,
            error: Some(format!("Failed to fetch note: {}", e)),
        }),
    }
}

async fn create_note(
    State(pool): State<SqlitePool>,
    Json(note): Json<Note>,
) -> Json<ApiResponse<Note>> {
    if let Err(e) = note.validate() {
        return Json(ApiResponse {
            success: false,
            data: None,
            error: Some(format!("Validation error: {}", e)),
        });
    }

    match sqlx::query_as::<_, Note>(
        "INSERT INTO notes (title, content) VALUES (?, ?) RETURNING id, title, content",
    )
    .bind(note.title)
    .bind(note.content)
    .fetch_one(&pool)
    .await
    {
        Ok(note) => Json(ApiResponse {
            success: true,
            data: Some(note),
            error: None,
        }),
        Err(e) => Json(ApiResponse {
            success: false,
            data: None,
            error: Some(format!("Failed to create note: {}", e)),
        }),
    }
}

async fn update_note(
    Path(id): Path<i64>,
    State(pool): State<SqlitePool>,
    Json(note): Json<Note>,
) -> Json<ApiResponse<Note>> {
    if let Err(e) = note.validate() {
        return Json(ApiResponse {
            success: false,
            data: None,
            error: Some(format!("Validation error: {}", e)),
        });
    }

    match sqlx::query_as::<_, Note>(
        "UPDATE notes SET title = ?, content = ? WHERE id = ? RETURNING id, title, content",
    )
    .bind(note.title)
    .bind(note.content)
    .bind(id)
    .fetch_one(&pool)
    .await
    {
        Ok(note) => Json(ApiResponse {
            success: true,
            data: Some(note),
            error: None,
        }),
        Err(e) => Json(ApiResponse {
            success: false,
            data: None,
            error: Some(format!("Failed to update note: {}", e)),
        }),
    }
}

async fn delete_note(
    Path(id): Path<i64>,
    State(pool): State<SqlitePool>,
) -> Json<ApiResponse<()>> {
    match sqlx::query("DELETE FROM notes WHERE id = ?")
        .bind(id)
        .execute(&pool)
        .await
    {
        Ok(_) => Json(ApiResponse {
            success: true,
            data: None,
            error: None,
        }),
        Err(e) => Json(ApiResponse {
            success: false,
            data: None,
            error: Some(format!("Failed to delete note: {}", e)),
