from flask import Flask, request, jsonify
from flask.logging import create_logger
import logging
from datetime import datetime

app = Flask(__name__)
log = create_logger(app)
app.logger.setLevel(logging.INFO)

# In-memory storage for books
books = []

class Book:
    def __init__(self, title, author, publication_date):
        self.title = title
        self.author = author
        self.publication_date = publication_date

    def to_dict(self):
        return {
            'title': self.title,
            'author': self.author,
            'publication_date': self.publication_date
        }

@app.before_request
def log_request_info():
    app.logger.info(f"Request: {request.method} {request.path}")

@app.route('/books', methods=['GET'])
def get_books():
    return jsonify([book.to_dict() for book in books]), 200

@app.route('/books', methods=['POST'])
def add_book():
    data = request.get_json()
    try:
        title = data['title']
        author = data['author']
        publication_date = data['publication_date']

        # Validate publication date format
        try:
            datetime.strptime(publication_date, '%Y-%m-%d')
        except ValueError:
            return jsonify({'error': 'Invalid date format. Use YYYY-MM-DD'}), 400

        book = Book(title, author, publication_date)
        books.append(book)
        return jsonify(book.to_dict()), 201
    except KeyError as e:
        return jsonify({'error': f'Missing required field: {str(e)}'}), 400
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/books/<int:index>', methods=['GET'])
def get_book(index):
    try:
        return jsonify(books[index].to_dict()), 200
    except IndexError:
        return jsonify({'error': 'Book not found'}), 404

@app.route('/books/<int:index>', methods=['PUT'])
def update_book(index):
    try:
        data = request.get_json()
        book = books[index]

        if 'title' in data:
            book.title = data['title']
        if 'author' in data:
            book.author = data['author']
        if 'publication_date' in data:
            try:
                datetime.strptime(data['publication_date'], '%Y-%m-%d')
                book.publication_date = data['publication_date']
            except ValueError:
                return jsonify({'error': 'Invalid date format. Use YYYY-MM-DD'}), 400

        return jsonify(book.to_dict()), 200
    except IndexError:
        return jsonify({'error': 'Book not found'}), 404
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/books/<int:index>', methods=['DELETE'])
def delete_book(index):
    try:
        books.pop(index)
        return '', 204
    except IndexError:
        return jsonify({'error': 'Book not found'}), 404

if __name__ == '__main__':
    app.run(debug=True)
