import { createApp, reactive, onMounted } from 'whatsup';
import { fetchUsers } from './api'; // Assume this is your API service

// User Listing Component
function UserList({ users, isLoading, error }) {
    if (isLoading) {
        return <div className="spinner">Loading...</div>;
    }

    if (error) {
        return <div className="error">{error}</div>;
    }

    return (
        <ul className="user-list">
            {users.map(user => (
                <li key={user.id}>
                    {user.name} - {user.email}
                </li>
            ))}
        </ul>
    );
}

// Main App Component
function App() {
    const state = reactive({
        users: [],
        isLoading: false,
        error: null,
    });

    const loadUsers = async () => {
        state.isLoading = true;
        state.error = null;

        try {
            const users = await fetchUsers(); // API call
            state.users = users;
        } catch (err) {
            state.error = 'Failed to fetch users. Please try again.';
        } finally {
            state.isLoading = false;
        }
    };

    onMounted(() => {
        loadUsers();
    });

    return (
        <div className="app">
            <h1>User List</h1>
            <UserList 
                users={state.users} 
                isLoading={state.isLoading} 
                error={state.error} 
            />
        </div>
    );
}

// Initialize the app
createApp(App).mount(document.getElementById('root'));
