#include <iostream>
#include <vector>
#include <unordered_map>
#include <queue>
#include <stdexcept>
#include <CGraph/CGraph.h>

using namespace CGraph;

class Task {
public:
    std::string name;
    std::function<void()> execute;

    Task(const std::string& name, const std::function<void()>& execute)
        : name(name), execute(execute) {}
};

class DAG {
private:
    std::unordered_map<std::string, Task*> tasks;
    std::unordered_map<std::string, std::vector<std::string>> adjList;
    std::unordered_map<std::string, int> inDegree;

public:
    void addTask(const std::string& name, const std::function<void()>& execute) {
        if (tasks.find(name) != tasks.end()) {
            throw std::runtime_error("Task already exists: " + name);
        }
        tasks[name] = new Task(name, execute);
        adjList[name] = std::vector<std::string>();
        inDegree[name] = 0;
    }

    void addDependency(const std::string& from, const std::string& to) {
        if (tasks.find(from) == tasks.end() || tasks.find(to) == tasks.end()) {
            throw std::runtime_error("Invalid task name in dependency");
        }
        adjList[from].push_back(to);
        inDegree[to]++;
    }

    std::vector<std::string> topologicalSort() {
        std::queue<std::string> q;
        std::vector<std::string> result;
        std::unordered_map<std::string, int> tempInDegree = inDegree;

        for (const auto& entry : tempInDegree) {
            if (entry.second == 0) {
                q.push(entry.first);
            }
        }

        while (!q.empty()) {
            std::string current = q.front();
            q.pop();
            result.push_back(current);

            for (const std::string& neighbor : adjList[current]) {
                tempInDegree[neighbor]--;
                if (tempInDegree[neighbor] == 0) {
                    q.push(neighbor);
                }
            }
        }

        if (result.size() != tasks.size()) {
            throw std::runtime_error("Cycle detected in the DAG");
        }

        return result;
    }

    void executeTasks() {
        GPipeline pipeline;
        std::vector<std::string> order = topologicalSort();

        for (const std::string& taskName : order) {
            pipeline.addElement([this, taskName]() {
                std::cout << "Executing task: " << taskName << std::endl;
                tasks[taskName]->execute();
                std::cout << "Completed task: " << taskName << std::endl;
            });
        }

        pipeline.process();
    }

    ~DAG() {
        for (auto& entry : tasks) {
            delete entry.second;
        }
    }
};

int main() {
    DAG dag;

    try {
        dag.addTask("A", []() { std::cout << "Task A output" << std::endl; });
        dag.addTask("B", []() { std::cout << "Task B output" << std::endl; });
        dag.addTask("C", []() { std::cout << "Task C output" << std::endl; });

        dag.addDependency("A", "B");
        dag.addDependency("B", "C");

        dag.executeTasks();
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
