// LibraryServer.java
package com.example.library;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class LibraryServer {
    private static final Logger logger = LoggerFactory.getLogger(LibraryServer.class);
    private final int port;
    private final Server server;

    public LibraryServer(int port) {
        this.port = port;
        this.server = ServerBuilder.forPort(port)
                .addService(new LibraryServiceImpl())
                .build();
    }

    public void start() throws IOException {
        server.start();
        logger.info("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server");
            LibraryServer.this.stop();
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        LibraryServer server = new LibraryServer(50051);
        server.start();
        server.blockUntilShutdown();
    }

    static class LibraryServiceImpl extends LibraryServiceGrpc.LibraryServiceImplBase {
        private final Map<String, Book> books = new ConcurrentHashMap<>();
        private final Logger logger = LoggerFactory.getLogger(LibraryServiceImpl.class);

        @Override
        public void addBook(AddBookRequest request, StreamObserver<AddBookResponse> responseObserver) {
            logger.info("Received request to add book: " + request.getBook().getTitle());
            try {
                String id = generateId();
                books.put(id, request.getBook());
                responseObserver.onNext(AddBookResponse.newBuilder().setId(id).build());
                responseObserver.onCompleted();
                logger.info("Book added successfully with ID: " + id);
            } catch (Exception e) {
                logger.error("Error adding book: " + e.getMessage());
                responseObserver.onError(e);
            }
        }

        @Override
        public void getBook(GetBookRequest request, StreamObserver<GetBookResponse> responseObserver) {
            logger.info("Received request to get book with ID: " + request.getId());
            try {
                Book book = books.get(request.getId());
                if (book == null) {
                    throw new RuntimeException("Book not found");
                }
                responseObserver.onNext(GetBookResponse.newBuilder().setBook(book).build());
                responseObserver.onCompleted();
                logger.info("Book retrieved successfully: " + book.getTitle());
            } catch (Exception e) {
                logger.error("Error retrieving book: " + e.getMessage());
                responseObserver.onError(e);
            }
        }

        @Override
        public void listBooks(ListBooksRequest request, StreamObserver<ListBooksResponse> responseObserver) {
            logger.info("Received request to list all books");
            try {
                ListBooksResponse.Builder responseBuilder = ListBooksResponse.newBuilder();
                books.values().forEach(responseBuilder::addBooks);
                responseObserver.onNext(responseBuilder.build());
                responseObserver.onCompleted();
                logger.info("Listed all books successfully");
            } catch (Exception e) {
                logger.error("Error listing books: " + e.getMessage());
                responseObserver.onError(e);
            }
        }

        private String generateId() {
            return java.util.UUID.randomUUID().toString();
        }
    }
}
