import logging
from datetime import datetime
from cornice import Service
from pyramid.config import Configurator
from pyramid.response import Response
from pyramid.view import view_config
from cornice.validators import colander_body_validator
import colander

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# In-memory storage for books
books = {}

# Schema for book validation
class BookSchema(colander.MappingSchema):
    title = colander.SchemaNode(colander.String())
    author = colander.SchemaNode(colander.String())
    isbn = colander.SchemaNode(colander.String())
    published_date = colander.SchemaNode(colander.String())

# Cornice services
book_service = Service(name='book', path='/books/{isbn}')
books_service = Service(name='books', path='/books')

@books_service.get()
def list_books(request):
    """List all books."""
    log_request(request)
    return {'books': list(books.values())}

@books_service.post(schema=BookSchema(), validators=(colander_body_validator,))
def create_book(request):
    """Create a new book."""
    log_request(request)
    book = request.validated
    if book['isbn'] in books:
        raise colander.Invalid(
            BookSchema(), 'Book with this ISBN already exists')
    books[book['isbn']] = book
    return Response(status=201, json_body=book)

@book_service.get()
def get_book(request):
    """Get a book by ISBN."""
    log_request(request)
    isbn = request.matchdict['isbn']
    if isbn not in books:
        raise colander.Invalid(BookSchema(), 'Book not found')
    return books[isbn]

@book_service.put(schema=BookSchema(), validators=(colander_body_validator,))
def update_book(request):
    """Update a book by ISBN."""
    log_request(request)
    isbn = request.matchdict['isbn']
    if isbn not in books:
        raise colander.Invalid(BookSchema(), 'Book not found')
    book = request.validated
    if book['isbn'] != isbn:
        raise colander.Invalid(BookSchema(), 'ISBN cannot be changed')
    books[isbn] = book
    return book

@book_service.delete()
def delete_book(request):
    """Delete a book by ISBN."""
    log_request(request)
    isbn = request.matchdict['isbn']
    if isbn not in books:
        raise colander.Invalid(BookSchema(), 'Book not found')
    del books[isbn]
    return Response(status=204)

def log_request(request):
    """Log request details."""
    logger.info({
        'method': request.method,
        'endpoint': request.path,
        'timestamp': datetime.utcnow().isoformat()
    })

def main(global_config, **settings):
    config = Configurator(settings=settings)
    config.include("cornice")
    config.scan()
    return config.make_wsgi_app()
