import org.tinylog.Logger;
import org.tinylog.configuration.Configuration;
import org.tinylog.Level;

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class UserRegistrationProcessor {

    static {
        // Configure tinylog for file logging with daily rotation
        Configuration.set("writer", "file");
        Configuration.set("writer.file", "logs/registration_{date}.log");
        Configuration.set("writer.format", "{date:yyyy-MM-dd HH:mm:ss} {level} {method} - {message}");
        Configuration.set("writer.level", "info");
        Configuration.set("writer.rollingpolicy", "daily");
    }

    public static void main(String[] args) {
        if (args.length == 0) {
            Logger.error("No CSV file path provided");
            return;
        }

        String csvFile = args[0];
        processRegistrations(csvFile);
    }

    private static void processRegistrations(String csvFile) {
        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            String line;
            while ((line = br.readLine()) != null) {
                processRegistration(line);
            }
        } catch (IOException e) {
            Logger.error(e, "Error reading CSV file");
        }
    }

    private static void processRegistration(String record) {
        String[] fields = record.split(",");
        if (fields.length < 2) {
            Logger.error("Invalid record format: {}", record);
            return;
        }

        String name = fields[0].trim();
        String email = fields[1].trim();

        if (name.isEmpty()) {
            Logger.error("Validation failed: Name is required for record - {}", record);
            return;
        }

        if (email.isEmpty()) {
            Logger.error("Validation failed: Email is required for record - {}", record);
            return;
        }

        if (!isValidEmail(email)) {
            Logger.error("Validation failed: Invalid email format for record - {}", record);
            return;
        }

        Logger.info("Successfully registered user: Name={}, Email={}", name, email);
    }

    private static boolean isValidEmail(String email) {
        return email.matches("^[\\w-\\.]+@([\\w-]+\\.)+[\\w-]{2,4}$");
    }
}
