// UserProfileServiceImpl.java
package userprofile;

import io.grpc.Status;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.HashMap;
import java.util.Map;
import java.util.UUID;

public class UserProfileServiceImpl extends UserProfileServiceGrpc.UserProfileServiceImplBase {
    private static final Logger logger = LoggerFactory.getLogger(UserProfileServiceImpl.class);
    private final Map<String, UserProfileResponse> userProfiles = new HashMap<>();

    @Override
    public void createUser(CreateUserRequest request, StreamObserver<UserProfileResponse> responseObserver) {
        logger.info("Received CreateUser request: {}", request);
        try {
            validateCreateRequest(request);
            String userId = UUID.randomUUID().toString();
            UserProfileResponse response = UserProfileResponse.newBuilder()
                    .setUserId(userId)
                    .setName(request.getName())
                    .setEmail(request.getEmail())
                    .setAge(request.getAge())
                    .build();
            userProfiles.put(userId, response);
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        } catch (IllegalArgumentException e) {
            logger.error("Invalid CreateUser request: {}", e.getMessage());
            responseObserver.onError(Status.INVALID_ARGUMENT
                    .withDescription(e.getMessage())
                    .asRuntimeException());
        }
    }

    @Override
    public void getUser(GetUserRequest request, StreamObserver<UserProfileResponse> responseObserver) {
        logger.info("Received GetUser request: {}", request);
        if (!userProfiles.containsKey(request.getUserId())) {
            logger.error("User not found: {}", request.getUserId());
            responseObserver.onError(Status.NOT_FOUND
                    .withDescription("User not found")
                    .asRuntimeException());
            return;
        }
        responseObserver.onNext(userProfiles.get(request.getUserId()));
        responseObserver.onCompleted();
    }

    @Override
    public void updateUser(UpdateUserRequest request, StreamObserver<UserProfileResponse> responseObserver) {
        logger.info("Received UpdateUser request: {}", request);
        try {
            validateUpdateRequest(request);
            if (!userProfiles.containsKey(request.getUserId())) {
                logger.error("User not found: {}", request.getUserId());
                responseObserver.onError(Status.NOT_FOUND
                        .withDescription("User not found")
                        .asRuntimeException());
                return;
            }
            UserProfileResponse updatedProfile = UserProfileResponse.newBuilder()
                    .setUserId(request.getUserId())
                    .setName(request.getName())
                    .setEmail(request.getEmail())
                    .setAge(request.getAge())
                    .build();
            userProfiles.put(request.getUserId(), updatedProfile);
            responseObserver.onNext(updatedProfile);
            responseObserver.onCompleted();
        } catch (IllegalArgumentException e) {
            logger.error("Invalid UpdateUser request: {}", e.getMessage());
            responseObserver.onError(Status.INVALID_ARGUMENT
                    .withDescription(e.getMessage())
                    .asRuntimeException());
        }
    }

    private void validateCreateRequest(CreateUserRequest request) {
        if (request.getName().isEmpty() || request.getEmail().isEmpty()) {
            throw new IllegalArgumentException("Name and email are required");
        }
        if (request.getAge() <= 0) {
            throw new IllegalArgumentException("Age must be positive");
        }
    }

    private void validateUpdateRequest(UpdateUserRequest request) {
        if (request.getName().isEmpty() || request.getEmail().isEmpty()) {
            throw new IllegalArgumentException("Name and email are required");
        }
        if (request.getAge() <= 0) {
            throw new IllegalArgumentException("Age must be positive");
        }
    }
}
