fn main() {
    App::new()
        .add_plugins(DefaultPlugins)
        .insert_resource(GameState {
            is_running: false,
            is_game_over: false,
        })
        .add_systems(Startup, setup)
        .add_systems(Update, (
            start_game,
            player_movement,
            collision_detection,
            update_health_text,
            check_game_over,
            restart_game,
        ).run_if(in_state(GameState {
            is_running: true,
            is_game_over: false,
        })))
        .run();
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    // Start screen
    commands.spawn((
        SpriteBundle {
            sprite: Sprite {
                color: Color::rgb(0.1, 0.1, 0.1),
                custom_size: Some(Vec2::new(800.0, 600.0)),
                ..default()
            },
            ..default()
        },
        StartScreen,
    ));

    commands.spawn((
        TextBundle::from_section(
            "Press SPACE to Start",
            TextStyle {
                font: asset_server.load("fonts/FiraSans-Bold.ttf"),
                font_size: 40.0,
                color: Color::WHITE,
            },
        )
        .with_text_alignment(TextAlignment::Center)
        .with_style(Style {
            position_type: PositionType::Absolute,
            top: Val::Px(300.0),
            left: Val::Px(0.0),
            right: Val::Px(0.0),
            ..default()
        }),
        StartScreen,
    ));
}

fn start_game(
    mut commands: Commands,
    keyboard_input: Res<Input<KeyCode>>,
    mut game_state: ResMut<GameState>,
    query: Query<Entity, With<StartScreen>>,
    asset_server: Res<AssetServer>,
) {
    if keyboard_input.just_pressed(KeyCode::Space) && !game_state.is_running {
        game_state.is_running = true;

        // Remove start screen
        for entity in query.iter() {
            commands.entity(entity).despawn();
        }

        // Spawn player
        commands.spawn((
            SpriteBundle {
                sprite: Sprite {
                    color: Color::BLUE,
                    custom_size: Some(Vec2::new(50.0, 50.0)),
                    ..default()
                },
                transform: Transform::from_xyz(0.0, 0.0, 0.0),
                ..default()
            },
            Player {
                speed: 300.0,
                health: 100,
            },
            GameScreen,
        ));

        // Spawn obstacles
        commands.spawn((
            SpriteBundle {
                sprite: Sprite {
                    color: Color::RED,
                    custom_size: Some(Vec2::new(100.0, 100.0)),
                    ..default()
                },
                transform: Transform::from_xyz(200.0, 100.0, 0.0),
                ..default()
            },
            Obstacle,
            GameScreen,
        ));

        commands.spawn((
            SpriteBundle {
                sprite: Sprite {
                    color: Color::RED,
                    custom_size: Some(Vec2::new(100.0, 100.0)),
                    ..default()
                },
                transform: Transform::from_xyz(-200.0, -100.0, 0.0),
                ..default()
            },
            Obstacle,
            GameScreen,
        ));

        // Health text
        commands.spawn((
            TextBundle::from_section(
                "Health: 100",
                TextStyle {
                    font: asset_server.load("fonts/FiraSans-Bold.ttf"),
                    font_size: 30.0,
                    color: Color::WHITE,
                },
            )
            .with_style(Style {
                position_type: PositionType::Absolute,
                top: Val::Px(10.0),
                left: Val::Px(10.0),
                ..default()
            }),
            HealthText,
            GameScreen,
        ));
    }
}

fn player_movement(
    keyboard_input: Res<Input<KeyCode>>,
    mut player_query: Query<(&mut Transform, &Player)>,
    time: Res<Time>,
) {
    for (mut transform, player) in player_query.iter_mut() {
        let mut direction = Vec3::ZERO;

        if keyboard_input.pressed(KeyCode::Left) || keyboard_input.pressed(KeyCode::A) {
            direction.x -= 1.0;
        }
        if keyboard_input.pressed(KeyCode::Right) || keyboard_input.pressed(KeyCode::D) {
            direction.x += 1.0;
        }
        if keyboard_input.pressed(KeyCode::Up) || keyboard_input.pressed(KeyCode::W) {
            direction.y += 1.0;
        }
        if keyboard_input.pressed(KeyCode::Down) || keyboard_input.pressed(KeyCode::S) {
            direction.y -= 1.0;
        }

        if direction.length() > 0.0 {
            direction = direction.normalize();
        }

        transform.translation += direction * player.speed * time.delta_seconds();
    }
}

fn collision_detection(
    mut player_query: Query<(&Transform, &mut Player), With<Player>>,
    obstacle_query: Query<&Transform, With<Obstacle>>,
) {
    for (player_transform, mut player) in player_query.iter_mut() {
        for obstacle_transform in obstacle_query.iter() {
            let distance = player_transform.translation.distance(obstacle_transform.translation);
            if distance < 75.0 { // Simple distance-based collision
                player.health -= 1;
            }
        }
    }
}

fn update_health_text(
    player_query: Query<&Player>,
    mut text_query: Query<&mut Text, With<HealthText>>,
) {
    for player in player_query.iter() {
        for mut text in text_query.iter_mut() {
            text.sections[0].value = format!("Health: {}", player.health);
        }
    }
}

fn check_game_over(
    player_query: Query<&Player>,
    mut game_state: ResMut<GameState>,
    mut commands: Commands,
    asset_server: Res<AssetServer>,
    game_screen_query: Query<Entity, With<GameScreen>>,
) {
    for player in player_query.iter() {
        if player.health <= 0 && !game_state.is_game_over {
            game_state.is_game_over = true;

            // Remove game screen entities
            for entity in game_screen_query.iter() {
                commands.entity(entity).despawn();
            }

            // Spawn game over screen
            commands.spawn((
                SpriteBundle {
                    sprite: Sprite {
                        color: Color::rgb(0.1, 0.1, 0.1),
                        custom_size: Some(Vec2::new(800.0, 600.0)),
                        ..default()
                    },
                    ..default()
                },
                GameOverScreen,
            ));

            commands.spawn((
                TextBundle::from_section(
                    "Game Over\nPress R to Restart",
                    TextStyle {
