import { h, app } from "whatsup"
import { map, filter, scan, startWith } from "whatsup/streams"

function* App() {
    const notes = yield* Notes()
    const [addNote, deleteNote] = yield* Actions()

    return () => (
        <div>
            <h1>Notes App</h1>
            <NoteForm onSubmit={addNote} />
            <NoteList notes={notes} onDelete={deleteNote} />
        </div>
    )
}

function* NoteForm({ onSubmit }) {
    const [text, setText] = yield* useState("")

    const handleSubmit = (e) => {
        e.preventDefault()
        onSubmit(text)
        setText("")
    }

    return () => (
        <form onSubmit={handleSubmit}>
            <input
                type="text"
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Enter note..."
                required
            />
            <button type="submit">Add Note</button>
        </form>
    )
}

function* NoteList({ notes, onDelete }) {
    return () => (
        <ul>
            {notes.map((note) => (
                <NoteItem key={note.id} note={note} onDelete={onDelete} />
            ))}
        </ul>
    )
}

function* NoteItem({ note, onDelete }) {
    const [showConfirm, setShowConfirm] = yield* useState(false)

    const handleDelete = () => {
        setShowConfirm(true)
    }

    const confirmDelete = () => {
        onDelete(note.id)
        setShowConfirm(false)
    }

    const cancelDelete = () => {
        setShowConfirm(false)
    }

    return () => (
        <li>
            {note.text}
            <button onClick={handleDelete}>Delete</button>
            {showConfirm && (
                <div>
                    <p>Are you sure?</p>
                    <button onClick={confirmDelete}>Yes</button>
                    <button onClick={cancelDelete}>No</button>
                </div>
            )}
        </li>
    )
}

function* Notes() {
    const notes = yield* useStream(
        scan(
            (notes, action) => {
                if (action.type === "ADD") {
                    return [...notes, { id: Date.now(), text: action.text }]
                }
                if (action.type === "DELETE") {
                    return notes.filter((note) => note.id !== action.id)
                }
                return notes
            },
            [],
            yield* Actions.pipe()
        ),
        []
    )

    return notes
}

function* Actions() {
    const actions = yield* useStream(
        startWith(null, yield* Actions.pipe())
    )

    const addNote = (text) => {
        actions.next({ type: "ADD", text })
    }

    const deleteNote = (id) => {
        actions.next({ type: "DELETE", id })
    }

    return [addNote, deleteNote]
}

Actions.pipe = function* () {
    const subject = yield* useSubject()
    return subject
}

function* useSubject() {
    const subject = yield* useState(new Subject())
    return subject
}

function* useStream(stream, initial) {
    const [value, setValue] = yield* useState(initial)
    yield* useEffect(() => {
        const sub = stream.subscribe(setValue)
        return () => sub.unsubscribe()
    }, [stream])
    return value
}

