class PasswordGeneratorController(Controller):
    class Meta:
        label = 'base'
        arguments = [
            (['-l', '--length'], {
                'help': 'Length of the password (12-64 chars)',
                'type': int,
                'default': 16
            }),
            (['-n', '--no-numbers'], {
                'help': 'Exclude numbers from the password',
                'action': 'store_true',
                'dest': 'no_numbers'
            }),
            (['-s', '--no-specials'], {
                'help': 'Exclude special symbols from the password',
                'action': 'store_true',
                'dest': 'no_specials'
            }),
        ]

    @ex(help='Generate a secure random password')
    def generate(self):
        try:
            # Validate password length
            if not 12 <= self.app.pargs.length <= 64:
                raise ValueError("Password length must be between 12 and 64 characters")

            # Define character sets
            chars = string.ascii_letters
            if not self.app.pargs.no_numbers:
                chars += string.digits
            if not self.app.pargs.no_specials:
                chars += string.punctuation

            # Generate password
            password = ''.join(random.SystemRandom().choice(chars) for _ in range(self.app.pargs.length))

            # Log generation attempt
            self.app.log.info(f"Generated password with length {self.app.pargs.length}")

            # Output success with color
            self.app.render({
                'password': password,
                'length': self.app.pargs.length
            }, 'success.txt')

        except ValueError as e:
            # Log error
            self.app.log.error(str(e))
            # Output error with color
            self.app.render({
                'error': str(e)
            }, 'error.txt')

class PasswordGeneratorApp(App):
    class Meta:
        label = 'password_generator'
        base_controller = PasswordGeneratorController
        handlers = [PasswordGeneratorController]
        log_handler = 'file'
        output_handler = 'mustache'

    def render(self, data, template):
        if template == 'success.txt':
            self.output.print(f"[green]Success![/green] Generated password: [bold]{data['password']}[/bold] (length: {data['length']})")
        elif template == 'error.txt':
            self.output.print(f"[red]Error:[/red] {data['error']}")

def main():
    with PasswordGeneratorApp() as app:
        app.run()

if __name__ == '__main__':
    main()
