#include <CGraph/CGraph.h>
#include <opencv2/opencv.hpp>
#include <filesystem>
#include <chrono>
#include <fstream>
#include <nlohmann/json.hpp>

using namespace CGraph;
namespace fs = std::filesystem;
using json = nlohmann::json;

class ImageLoader : public GNode {
public:
    ImageLoader(const std::string& dir_path) : dir_path_(dir_path) {}

    CStatus init() override {
        if (!fs::exists(dir_path_)) {
            return CStatus(FILE_NOT_EXIST, "Directory does not exist");
        }
        return CStatus();
    }

    CStatus run() override {
        auto start = std::chrono::high_resolution_clock::now();

        for (const auto& entry : fs::directory_iterator(dir_path_)) {
            if (entry.path().extension() == ".jpg" || entry.path().extension() == ".png") {
                cv::Mat img = cv::imread(entry.path().string());
                if (img.empty()) {
                    errors_.push_back("Failed to load: " + entry.path().string());
                    continue;
                }
                images_.push_back(img);
                filenames_.push_back(entry.path().filename().string());
            }
        }

        if (images_.empty()) {
            return CStatus(FILE_NOT_EXIST, "No valid images found");
        }

        auto end = std::chrono::high_resolution_clock::now();
        exec_time_ = std::chrono::duration_cast<std::chrono::milliseconds>(end - start).count();

        return CStatus();
    }

    std::vector<cv::Mat> images_;
    std::vector<std::string> filenames_;
    std::vector<std::string> errors_;
    long exec_time_ = 0;

private:
    std::string dir_path_;
};

class ImageFilter : public GNode {
public:
    CStatus run() override {
        auto start = std::chrono::high_resolution_clock::now();

        auto* loader = dynamic_cast<ImageLoader*>(this->getDependency()[0]);
        if (!loader) return CStatus(STATUS_FAULT);

        for (auto& img : loader->images_) {
            cv::cvtColor(img, img, cv::COLOR_BGR2GRAY);
        }

        auto end = std::chrono::high_resolution_clock::now();
        exec_time_ = std::chrono::duration_cast<std::chrono::milliseconds>(end - start).count();

        return CStatus();
    }

    long exec_time_ = 0;
};

class ImageSaver : public GNode {
public:
    ImageSaver(const std::string& output_dir) : output_dir_(output_dir) {}

    CStatus init() override {
        if (!fs::exists(output_dir_)) {
            fs::create_directory(output_dir_);
        }
        return CStatus();
    }

    CStatus run() override {
        auto start = std::chrono::high_resolution_clock::now();

        auto* loader = dynamic_cast<ImageLoader*>(this->getDependency()[0]);
        if (!loader) return CStatus(STATUS_FAULT);

        for (size_t i = 0; i < loader->images_.size(); ++i) {
            std::string output_path = output_dir_ + "/processed_" + loader->filenames_[i];
            if (!cv::imwrite(output_path, loader->images_[i])) {
                loader->errors_.push_back("Failed to save: " + output_path);
            }
        }

        auto end = std::chrono::high_resolution_clock::now();
        exec_time_ = std::chrono::duration_cast<std::chrono::milliseconds>(end - start).count();

        return CStatus();
    }

    long exec_time_ = 0;

private:
    std::string output_dir_;
};

int main() {
    GPipelinePtr pipeline = GPipelineFactory::create();

    auto loader = pipeline->createGNode<ImageLoader>("./input_images");
    auto filter = pipeline->createGNode<ImageFilter>();
    auto saver = pipeline->createGNode<ImageSaver>("./output_images");

    pipeline->addGNode(loader, {});
    pipeline->addGNode(filter, {loader});
    pipeline->addGNode(saver, {filter});

    pipeline->setThreadPoolConfig(4);  // 4 threads for parallel processing
    pipeline->setDependence(CGraph::GDependenceMode::STRICT_MODE);

    pipeline->init();
    pipeline->run();

    // Collect statistics
    json stats;
    stats["elements"] = {
        {"ImageLoader", {
            {"execution_time_ms", loader->exec_time_},
            {"images_processed", loader->images_.size()},
            {"errors", loader->errors_}
        }},
        {"ImageFilter", {
            {"execution_time_ms", filter->exec_time_}
        }},
        {"ImageSaver", {
            {"execution_time_ms", saver->exec_time_},
            {"errors", loader->errors_}
        }}
    };
    stats["total_time_ms"] = loader->exec_time_ + filter->exec_time_ + saver->exec_time_;

    std::ofstream out("stats.json");
    out << stats.dump(4);
    out.close();

    return 0;
}
