// Proto file (inventory.proto)
syntax = "proto3";

option java_multiple_files = true;
option java_package = "com.example.inventory";
option java_outer_classname = "InventoryProto";

package inventory;

service InventoryService {
  rpc UpdateStock(StockUpdateRequest) returns (StockUpdateResponse) {}
  rpc StreamLowStockAlerts(Empty) returns (stream LowStockAlert) {}
}

message StockUpdateRequest {
  string product_id = 1;
  int32 quantity = 2;
}

message StockUpdateResponse {
  bool success = 1;
  int32 current_stock = 2;
}

message LowStockAlert {
  string product_id = 1;
  int32 current_quantity = 2;
  int32 threshold = 3;
}

message Empty {}

// Server Implementation (InventoryServer.java)
import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.health.v1.HealthCheckResponse.ServingStatus;
import io.grpc.health.v1.HealthGrpc;
import io.grpc.protobuf.services.HealthStatusManager;
import io.grpc.protobuf.services.ProtoReflectionService;
import io.prometheus.client.CollectorRegistry;
import io.prometheus.client.Counter;
import io.prometheus.client.Histogram;
import io.prometheus.client.exporter.HTTPServer;
import inventory.InventoryProto.*;
import inventory.InventoryServiceGrpc.InventoryServiceImplBase;
import io.grpc.stub.StreamObserver;
import java.io.IOException;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;

public class InventoryServer extends InventoryServiceImplBase {
    private final ConcurrentHashMap<String, Integer> inventory = new ConcurrentHashMap<>();
    private final int port;
    private Server server;
    private final HealthStatusManager healthManager;
    private final HTTPServer prometheusServer;

    // Prometheus metrics
    private static final Counter rpcCount = Counter.build()
        .name("grpc_rpc_count")
        .help("Count of RPC calls")
        .labelNames("method")
        .register();

    private static final Histogram rpcLatency = Histogram.build()
        .name("grpc_rpc_latency_seconds")
        .help("RPC latency in seconds")
        .labelNames("method")
        .register();

    public InventoryServer(int port, int prometheusPort) throws IOException {
        this.port = port;
        this.healthManager = new HealthStatusManager();
        this.prometheusServer = new HTTPServer(prometheusPort);

        // Initialize with some products
        inventory.put("prod1", 50);
        inventory.put("prod2", 30);
        inventory.put("prod3", 10);
    }

    @Override
    public void updateStock(StockUpdateRequest request, StreamObserver<StockUpdateResponse> responseObserver) {
        Histogram.Timer timer = rpcLatency.labels("UpdateStock").startTimer();
        rpcCount.labels("UpdateStock").inc();

        try {
            String productId = request.getProductId();
            int quantity = request.getQuantity();

            inventory.compute(productId, (k, v) -> v == null ? quantity : v + quantity);
            int currentStock = inventory.get(productId);

            // Check for low stock
            if (currentStock < 15) {
                // In a real system, this would trigger an alert
            }

            responseObserver.onNext(StockUpdateResponse.newBuilder()
                .setSuccess(true)
                .setCurrentStock(currentStock)
                .build());
            responseObserver.onCompleted();
        } finally {
            timer.observeDuration();
        }
    }

    @Override
    public void streamLowStockAlerts(Empty request, StreamObserver<LowStockAlert> responseObserver) {
        rpcCount.labels("StreamLowStockAlerts").inc();

        // Simulate periodic low stock checks
        new Thread(() -> {
            while (!Thread.currentThread().isInterrupted()) {
                inventory.forEach((productId, quantity) -> {
                    if (quantity < 15) {
                        responseObserver.onNext(LowStockAlert.newBuilder()
                            .setProductId(productId)
                            .setCurrentQuantity(quantity)
                            .setThreshold(15)
                            .build());
                    }
                });

                try {
                    Thread.sleep(5000); // Check every 5 seconds
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
            }
        }).start();
    }

    public void start() throws IOException {
        server = ServerBuilder.forPort(port)
            .addService(this)
            .addService(healthManager.getHealthService())
            .addService(ProtoReflectionService.newInstance())
            .build()
            .start();

        healthManager.setStatus("", ServingStatus.SERVING);

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            try {
                InventoryServer.this.stop();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            healthManager.setStatus("", ServingStatus.NOT_SERVING);
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
            prometheusServer.stop();
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        InventoryServer server = new InventoryServer(50051, 9090);
        server.start();
        server.blockUntilShutdown();
    }
}

// Client Implementation (InventoryClient.java)
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.stub.StreamObserver;
import inventory.InventoryProto.*;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicBoolean;

public class InventoryClient {
    private final ManagedChannel channel;
    private final InventoryServiceGrpc.InventoryServiceBlockingStub blockingStub;
    private final InventoryServiceGrpc.InventoryServiceStub asyncStub;

    public InventoryClient(String host, int port) {
        this(ManagedChannelBuilder.forAddress(host, port)
            .useTransportSecurity() // Enable TLS
            .defaultLoadBalancingPolicy("round_robin") // Client-side LB
            .build());
    }

    public InventoryClient(ManagedChannel channel) {
        this.channel = channel;
        this.blockingStub = InventoryServiceGrpc.newBlockingStub(channel)
            .withDeadlineAfter(5, TimeUnit.SECONDS); // Deadline for calls
        this.asyncStub = InventoryServiceGrpc.newStub(channel);
    }

    public void updateStock(String productId, int quantity) {
        try {
            StockUpdateResponse response = blockingStub.updateStock(
                StockUpdateRequest.newBuilder()
                    .setProductId(productId)
                    .setQuantity(quantity)
                    .build());

            System.out.println("Update successful: " + response.getSuccess() + 
                              ", Current stock: " + response.getCurrentStock());
        } catch (StatusRuntimeException e) {
            System.err.println("RPC failed: " + e.getStatus());
        }
    }

    public void streamLowStockAlerts() {
        final AtomicBoolean completed = new AtomicBoolean(false);

        StreamObserver<LowStockAlert> responseObserver = new StreamObserver<LowStockAlert>() {
            @Override
            public void onNext(LowStockAlert alert) {
                System.out.println("Low stock alert: " + alert.getProductId() + 
                                 " (current: " + alert.getCurrentQuantity() + 
                                 ", threshold: " + alert.getThreshold() + ")");
            }

            @Override
            public void onError(Throwable t) {
                System.err.println("Error in streaming: " + t.getMessage());
                completed.set(true);
            }

            @Override
            public void onCompleted() {
                System.out.println("Stream completed");
                completed.set(true);
            }
        };

        asyncStub.streamLowStockAlerts(Empty.newBuilder().build(), responseObserver);

        // Wait for completion (in real app, you'd handle this differently)
        while (!completed.get()) {
            try {
                Thread.sleep(1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public static void main(String[] args) throws InterruptedException {
        InventoryClient client = new InventoryClient("localhost", 50051);

        try {
            // Demonstrate unary RPC
            client.updateStock("prod1", -5);

            // Demonstrate server streaming RPC
            client.streamLowStockAlerts();
        } finally {
            client.shutdown();
        }
    }
}
