const ErrorFallback = ({ error }) => <div>Error: {error.message}</div>;

// Post component
const Post = ({ content, initialLikes, onLike }) => {
  const [likes, setLikes] = useState(initialLikes);
  const { logInteraction } = useEngagementTracker();

  const handleLike = () => {
    setLikes(likes + 1);
    onLike();
    logInteraction();
  };

  return (
    <div className="post">
      <p>{content}</p>
      <button onClick={handleLike}>Like ({likes})</button>
    </div>
  );
};

// CommentSection component
const CommentSection = ({ postId }) => {
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState('');
  const { logInteraction } = useEngagementTracker();

  useEffect(() => {
    const ws = new WebSocket(`wss://api.example.com/comments?postId=${postId}`);
    ws.onmessage = (event) => {
      setComments(JSON.parse(event.data));
    };

    return () => ws.close();
  }, [postId]);

  const handleCommentSubmit = () => {
    // API call would go here
    setComments([...comments, newComment]);
    setNewComment('');
    logInteraction();
  };

  return (
    <div className="comments">
      {comments.map((comment, i) => (
        <div key={i}>{comment}</div>
      ))}
      <input
        value={newComment}
        onChange={(e) => setNewComment(e.target.value)}
      />
      <button onClick={handleCommentSubmit}>Add Comment</button>
    </div>
  );
};

// Lazy-loaded post generator
function* postGenerator(posts) {
  for (const post of posts) {
    yield (
      <ErrorBoundary FallbackComponent={ErrorFallback} key={post.id}>
        <Post 
          content={post.content} 
          initialLikes={post.likes} 
          onLike={() => {/* Update like count via API */}}
        />
        <CommentSection postId={post.id} />
      </ErrorBoundary>
    );
  }
}

// Feed component
const Feed = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [postIterator, setPostIterator] = useState(null);

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const response = await fetch('https://api.example.com/posts');
        const data = await response.json();
        setPosts(data);
        setPostIterator(postGenerator(data));
      } catch (error) {
        console.error('Failed to load posts:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchPosts();

    const ws = new WebSocket('wss://api.example.com/feed');
    ws.onmessage = (event) => {
      setPosts(prev => [...prev, JSON.parse(event.data)]);
      setPostIterator(postGenerator([...posts, JSON.parse(event.data)]));
    };

    return () => ws.close();
  }, []);

  if (loading) return <div>Loading...</div>;

  return (
    <div className="feed">
      <Suspense fallback={<div>Loading post...</div>}>
        {postIterator && [...postIterator]}
      </Suspense>
    </div>
  );
};

export default Feed;
