// stores/configurator.js
import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import api from '@/api';

export const useConfiguratorStore = defineStore('configurator', () => {
  const currentConfiguration = ref({
    color: null,
    material: null,
    options: []
  });

  const basePrice = ref(100);
  const priceModifiers = ref({
    color: 0,
    material: 0,
    options: 0
  });

  const totalPrice = computed(() => {
    return basePrice.value + 
      priceModifiers.value.color + 
      priceModifiers.value.material + 
      priceModifiers.value.options;
  });

  function setColor(color) {
    currentConfiguration.value.color = color;
    priceModifiers.value.color = color.priceModifier || 0;
  }

  function setMaterial(material) {
    currentConfiguration.value.material = material;
    priceModifiers.value.material = material.priceModifier || 0;
  }

  async function saveConfiguration() {
    await api.saveConfiguration(currentConfiguration.value);
  }

  return {
    currentConfiguration,
    totalPrice,
    setColor,
    setMaterial,
    saveConfiguration
  };
});
