```go
package main

import (
	"context"
	"log"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/jwtauth/v5"
	"github.com/go-chi/render"
	"github.com/gocot/cot"
	"github.com/gocot/cot/db"
	"github.com/gocot/cot/logging"
	"github.com/gocot/cot/validator"
	"golang.org/x/time/rate"
)

var tokenAuth *jwtauth.JWTAuth

func init() {
	tokenAuth = jwtauth.New("HS256", []byte("secret"), nil)
}

type User struct {
	cot.Model
	Email    string `json:"email" cot:"unique;not null"`
	Password string `json:"password" cot:"not null"`
	Role     string `json:"role" cot:"default:'candidate'"`
}

type Job struct {
	cot.Model
	Title       string `json:"title" cot:"not null"`
	Description string `json:"description" cot:"not null"`
	Location    string `json:"location" cot:"not null"`
	SalaryMin   int    `json:"salary_min" cot:"not null"`
	SalaryMax   int    `json:"salary_max" cot:"not null"`
	EmployerID  uint   `json:"employer_id" cot:"not null"`
}

type AuthRequest struct {
	Email    string `json:"email" validate:"required,email"`
	Password string `json:"password" validate:"required,min=8"`
}

type JobRequest struct {
	Title       string `json:"title" validate:"required"`
	Description string `json:"description" validate:"required"`
	Location    string `json:"location" validate:"required"`
	SalaryMin   int    `json:"salary_min" validate:"required"`
	SalaryMax   int    `json:"salary_max" validate:"required"`
}

type SearchParams struct {
	Location  string `json:"location"`
	Keyword   string `json:"keyword"`
	MinSalary int    `json:"min_salary"`
	MaxSalary int    `json:"max_salary"`
}

func main() {
	app := cot.New()

	// Database setup
	db, err := db.NewPostgresDB("postgres://user:pass@localhost:5432/jobboard")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	// Migrations
	if err := db.AutoMigrate(&User{}, &Job{}); err != nil {
		log.Fatal(err)
	}

	// Middleware
	app.Use(middleware.RequestID)
	app.Use(middleware.RealIP)
	app.Use(logging.StructuredLogger)
	app.Use(middleware.Recoverer)
	app.Use(render.SetContentType(render.ContentTypeJSON))

	// Routes
	app.Route("/api", func(r chi.Router) {
		// Auth endpoints with rate limiting
		r.Group(func(r chi.Router) {
			r.Use(middleware.NewLimiter(rate.Every(time.Minute), 10).Middleware)
			r.Post("/register", register)
			r.Post("/login", login)
		})

		// Protected routes
		r.Group(func(r chi.Router) {
			r.Use(jwtauth.Verifier(tokenAuth))
			r.Use(jwtauth.Authenticator)

			// Job CRUD operations
			r.Route("/jobs", func(r chi.Router) {
				r.Get("/", listJobs)
				r.Post("/", createJob)
				r.Route("/{id}", func(r chi.Router) {
					r.Get("/", getJob)
					r.With(employerOnly).Put("/", updateJob)
					r.With(employerOnly).Delete("/", deleteJob)
				})
			})

			// Search endpoint
			r.Get("/search", searchJobs)
		})
	})

	app.Run(":8080")
}

func register(w cot.ResponseWriter, r *cot.Request) {
	var req AuthRequest
	if err := validator.Validate(r, &req); err != nil {
		render.Render(w, r, cot.ErrInvalidRequest(err))
		return
	}

	hashedPassword, err := cot.HashPassword(req.Password)
	if err != nil {
		render.Render(w, r, cot.ErrInternalServer(err))
		return
	}

	user := User{
		Email:    req.Email,
		Password: hashedPassword,
	}

	if err := cot.DB(r).Create(&user).Error; err != nil {
		render.Render(w, r, cot.ErrConflict(err))
		return
	}

	render.JSON(w, r, cot.Map{"message": "User created successfully"})
}

func login(w cot.ResponseWriter, r *cot.Request) {
	var req AuthRequest
	if err := validator.Validate(r, &req); err != nil {
		render.Render(w, r, cot.ErrInvalidRequest(err))
		return
	}

	var user User
	if err := cot.DB(r).Where("email = ?", req.Email).First(&user).Error; err != nil {
		render.Render(w, r, cot.ErrUnauthorized(err))
		return
	}

	if !cot.CheckPasswordHash(req.Password, user.Password) {
		render.Render(w, r, cot.ErrUnauthorized(nil))
		return
	}

	_, tokenString, err := tokenAuth.Encode(cot.Map{"user_id": user.ID, "role": user.Role})
	if err != nil {
		render.Render(w, r, cot.ErrInternalServer(err))
		return
	}

	render.JSON(w, r, cot.Map{"token": tokenString})
}

func createJob(w cot.ResponseWriter, r *cot.Request) {
	claims, _ := r.Context().Value(jwtauth.ContextKey).(cot.Map)
	employerID := uint(claims["user_id"].(float64))

	var req JobRequest
	if err := validator.Validate(r, &req); err != nil {
		render.Render(w, r, cot.ErrInvalidRequest(err))
		return
	}

	job := Job{
		Title:       req.Title,
		Description: req.Description,
		Location:    req.Location,
		SalaryMin:   req.SalaryMin,
		SalaryMax:   req.SalaryMax,
		EmployerID:  employerID,
	}

	if err := cot.DB(r).Create(&job).Error; err != nil {
		render.Render(w, r, cot.ErrInternalServer(err))
		return
	}

	render.JSON(w, r, job)
}

func listJobs(w cot.ResponseWriter, r *cot.Request) {
	var jobs []Job
	if err := cot.DB(r).Find(&jobs).Error; err != nil {
		render.Render(w, r, cot.ErrInternalServer(err))
		return
	}
	render.JSON(w, r, jobs)
}

func getJob(w cot.ResponseWriter, r *cot.Request) {
	id := chi.URLParam(r, "id")
	var job Job
	if err := cot.DB(r).First(&job, id).Error; err != nil {
		render.Render(w, r, cot.ErrNotFound(err))
		return
	}
	render.JSON(w, r, job)
}

func updateJob(w cot.ResponseWriter, r *cot.Request) {
	id := chi.URLParam(r, "id")
	claims, _ := r.Context().Value(jwtauth.ContextKey).(cot.Map)
	employerID := uint(claims["user_id"].(float64))

	var job Job
	if err := cot.DB(r).First(&job, id).Error; err != nil {
		render.Render(w, r, cot.ErrNotFound(err))
		return
	}

	if job.EmployerID != employerID {
		render.Render(w, r, cot.ErrForbidden(nil))
		return
	}

	var req JobRequest
	if err := validator.Validate(r, &req); err != nil {
		render.Render(w, r, cot.ErrInvalidRequest(err))
		return
	}

	job.Title = req.Title
	job.Description = req.Description
	job.Location = req.Location
	job.SalaryMin = req.SalaryMin
	job.SalaryMax = req.SalaryMax

	if err := cot.DB(r).Save(&job).Error; err != nil {
		render.Render(w, r, cot.ErrInternalServer(err))
		return
	}

	render.JSON(w, r, job)
}

func deleteJob(w cot.ResponseWriter, r *cot.Request) {
	id := chi.URLParam(r, "id")
	claims, _ := r.Context().Value(jwtauth.ContextKey).(cot.Map)
	employerID := uint(claims["user_id"].(float64))

	var job Job
	if err := cot.DB(r).First(&job, id).Error; err != nil {
		render.Render(w, r, cot.ErrNotFound(err))
		return
	}

	if job.EmployerID != employerID {
		render.Render(w, r, cot.ErrForbidden(nil))
		return
	}

	if err := cot.DB(r).Delete(&job).Error; err != nil {
		render.Render(w, r, cot.ErrInternalServer(err))
		return
	}

	render.JSON(w, r, cot.Map{"message": "Job deleted successfully"})
}

func searchJobs(w cot.ResponseWriter, r *cot.Request) {
	var params SearchParams
	if err := validator.ValidateQuery(r, &params); err != nil {
		render.Render(w, r, cot.ErrInvalidRequest(err))
		return
	}

	query := cot.DB(r).Model(&Job{})
	if params.Location != "" {
		query = query.Where("location ILIKE ?", "%"+params.Location+"%")
	}
	if params.Keyword != "" {
		query = query.Where("title ILIKE ? OR description ILIKE ?", "%"+params.Keyword+"%", "%"+params.Keyword+"%")
	}
	if params.MinSalary > 0 {
		query = query.Where("salary_max >= ?", params.MinSalary)
	}
	if params.MaxSalary > 0 {
		query = query.Where("salary_min <= ?", params.MaxSalary)
	}

	var jobs []Job
	if err := query.Find(&jobs).Error; err != nil {
		render.Render(w, r, cot.ErrInternalServer(err))
		return
	}

	render.JSON(w, r, jobs)
}

func employerOnly(next cot.HandlerFunc) cot.HandlerFunc {
	return func(w cot.ResponseWriter, r *cot.Request) {
		claims, _ := r.Context().Value(jwtauth.ContextKey).(cot.Map)
		if claims["role"] != "employer" {
			render.Render(w, r, cot.ErrForbidden(nil))
			return
		}
		next(w, r)
	}
}
