```rust
use bevy::prelude::*;
use bevy::window::WindowResized;
use bevy::sprite::MaterialMesh2dBundle;
use bevy::audio::{Audio, AudioPlugin, PlaybackSettings};
use serde::{Serialize, Deserialize};
use std::fs;

// Game states
#[derive(Debug, Clone, Copy, Default, Eq, PartialEq, Hash, States)]
enum GameState {
    #[default]
    Menu,
    Playing,
    GameOver,
}

// Difficulty levels
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
enum Difficulty {
    Easy,
    Medium,
    Hard,
}

// Game config
#[derive(Resource, Serialize, Deserialize)]
struct GameConfig {
    difficulty: Difficulty,
    high_score: u32,
}

// Components
#[derive(Component)]
struct Player {
    health: u32,
    speed: f32,
}

#[derive(Component)]
struct Projectile {
    speed: f32,
    damage: u32,
}

#[derive(Component)]
struct Enemy {
    health: u32,
    speed: f32,
    points: u32,
}

#[derive(Component)]
struct Collider {
    size: Vec2,
}

#[derive(Component)]
struct Explosion {
    timer: Timer,
}

#[derive(Component)]
struct HealthText;
#[derive(Component)]
struct ScoreText;

#[derive(Component)]
struct ShipDamageState {
    current: u32,
    max: u32,
    timer: Timer,
}

#[derive(Event)]
struct CollisionEvent {
    entity1: Entity,
    entity2: Entity,
}

#[derive(Event)]
struct SpawnWaveEvent;

#[derive(Resource)]
struct GameAssets {
    ship_textures: Vec<Handle<Image>>,
    explosion_texture: Handle<Image>,
    projectile_texture: Handle<Image>,
    enemy_textures: Vec<Handle<Image>>,
    shoot_sound: Handle<AudioSource>,
    explosion_sound: Handle<AudioSource>,
    font: Handle<Font>,
}

#[derive(Resource)]
struct Score(u32);

fn main() {
    App::new()
        .add_plugins(DefaultPlugins.set(WindowPlugin {
            primary_window: Some(Window {
                title: "Space Shooter".into(),
                ..default()
            }),
            ..default()
        }))
        .add_state::<GameState>()
        .add_event::<CollisionEvent>()
        .add_event::<SpawnWaveEvent>()
        .init_resource::<Score>()
        .add_systems(Startup, (setup_game, load_assets, load_config))
        .add_systems(OnEnter(GameState::Playing), setup_level)
        .add_systems(
            Update,
            (
                player_movement,
                fire_projectiles,
                enemy_ai,
                spawn_waves,
                collision_detection,
                handle_collisions,
                update_ui,
                animate_explosions,
                update_ship_damage_state,
                handle_window_resize,
                game_state_input,
            )
                .run_if(in_state(GameState::Playing)),
        )
        .add_systems(OnExit(GameState::Playing), cleanup_level)
        .run();
}

fn setup_game(mut commands: Commands) {
    commands.spawn(Camera2dBundle::default());
}

fn load_assets(mut commands: Commands, asset_server: Res<AssetServer>) {
    let assets = GameAssets {
        ship_textures: vec![
            asset_server.load("ships/ship1.png"),
            asset_server.load("ships/ship_damaged1.png"),
            asset_server.load("ships/ship_damaged2.png"),
        ],
        explosion_texture: asset_server.load("explosion.png"),
        projectile_texture: asset_server.load("projectile.png"),
        enemy_textures: vec![
            asset_server.load("enemies/enemy1.png"),
            asset_server.load("enemies/enemy2.png"),
        ],
        shoot_sound: asset_server.load("sounds/shoot.wav"),
        explosion_sound: asset_server.load("sounds/explosion.wav"),
        font: asset_server.load("fonts/FiraSans-Bold.ttf"),
    };
    commands.insert_resource(assets);
}

fn load_config(mut commands: Commands) {
    let config = fs::read_to_string("config.ron")
        .map(|s| ron::from_str::<GameConfig>(&s).unwrap_or_default())
        .unwrap_or_else(|_| GameConfig {
            difficulty: Difficulty::Medium,
            high_score: 0,
        });
    commands.insert_resource(config);
}

fn setup_level(
    mut commands: Commands,
    assets: Res<GameAssets>,
    mut score: ResMut<Score>,
) {
    score.0 = 0;

    // Spawn player
    commands.spawn((
        SpriteBundle {
            texture: assets.ship_textures[0].clone(),
            transform: Transform::from_xyz(0.0, -200.0, 0.0),
            ..default()
        },
        Player {
            health: 100,
            speed: 300.0,
        },
        Collider {
            size: Vec2::new(32.0, 32.0),
        },
        ShipDamageState {
            current: 0,
            max: 2,
            timer: Timer::from_seconds(0.5, TimerMode::Once),
        },
    ));

    // UI
    commands.spawn((
        TextBundle::from_sections([
            TextSection::new(
                "Health: ",
                TextStyle {
                    font: assets.font.clone(),
                    font_size: 20.0,
                    color: Color::WHITE,
                },
            ),
            TextSection::from_style(TextStyle {
                font: assets.font.clone(),
                font_size: 20.0,
                color: Color::RED,
            }),
        ])
        .with_style(Style {
            position_type: PositionType::Absolute,
            top: Val::Px(10.0),
            left: Val::Px(10.0),
            ..default()
        }),
        HealthText,
    ));

    commands.spawn((
