fn collision_detection(
    mut collision_events: EventWriter<CollisionEvent>,
    query: Query<(Entity, &Transform, &Collider)>,
) {
    let mut entities: Vec<_> = query.iter().collect();

    for i in 0..entities.len() {
        let (entity1, transform1, collider1) = entities[i];

        for j in (i + 1)..entities.len() {
            let (entity2, transform2, collider2) = entities[j];

            let distance = transform1.translation.truncate() - transform2.translation.truncate();
            let min_distance = (collider1.size + collider2.size) * 0.5;

            if distance.abs().cmplt(min_distance).all() {
                collision_events.send(CollisionEvent { entity1, entity2 });
            }
        }
    }
}

fn handle_collisions(
    mut commands: Commands,
    mut collision_events: EventReader<CollisionEvent>,
    mut player_query: Query<(Entity, &mut Player, &mut ShipDamageState)>,
    mut enemy_query: Query<(Entity, &mut Enemy)>,
    projectile_query: Query<&Projectile>,
    mut score: ResMut<Score>,
    assets: Res<GameAssets>,
    audio: Res<Audio>,
) {
    for event in collision_events.read() {
        let mut player_hit = false;
        let mut enemy_hit = false;
        let mut projectile_hit = false;

        // Check if player is involved
        if let Ok((player_entity, mut player, mut damage_state)) = player_query.get_mut(event.entity1) {
            player_hit = true;
            if projectile_query.get(event.entity2).is_ok() {
                player.health = player.health.saturating_sub(10);
                damage_state.current = (damage_state.current + 1).min(damage_state.max);
                damage_state.timer.reset();
                commands.entity(event.entity2).despawn();
            }
        } else if let Ok((player_entity, mut player, mut damage_state)) = player_query.get_mut(event.entity2) {
            player_hit = true;
            if projectile_query.get(event.entity1).is_ok() {
                player.health = player.health.saturating_sub(10);
                damage_state.current = (damage_state.current + 1).min(damage_state.max);
                damage_state.timer.reset();
                commands.entity(event.entity1).despawn();
            }
        }

        // Check if enemy is involved
        if let Ok((enemy_entity, mut enemy)) = enemy_query.get_mut(event.entity1) {
            enemy_hit = true;
            if projectile_query.get(event.entity2).is_ok() {
                enemy.health = enemy.health.saturating_sub(10);
                commands.entity(event.entity2).despawn();
            }
        } else if let Ok((enemy_entity, mut enemy)) = enemy_query.get_mut(event.entity2) {
            enemy_hit = true;
            if projectile_query.get(event.entity1).is_ok() {
                enemy.health = enemy.health.saturating_sub(10);
                commands.entity(event.entity1).despawn();
            }
        }

        // Handle enemy death
        if enemy_hit {
            if let Ok((enemy_entity, enemy)) = enemy_query.get_mut(event.entity1) {
                if enemy.health == 0 {
                    score.0 += enemy.points;
                    spawn_explosion(&mut commands, &assets, enemy_entity);
                    audio.play_with_settings(
                        assets.explosion_sound.clone(),
                        PlaybackSettings::ONCE.with_volume(0.3),
                    );
                    commands.entity(enemy_entity).despawn();
                }
            } else if let Ok((enemy_entity, enemy)) = enemy_query.get_mut(event.entity2) {
                if enemy.health == 0 {
                    score.0 += enemy.points;
                    spawn_explosion(&mut commands, &assets, enemy_entity);
                    audio.play_with_settings(
                        assets.explosion_sound.clone(),
                        PlaybackSettings::ONCE.with_volume(0.3),
                    );
                    commands.entity(enemy_entity).despawn();
                }
            }
        }

        // Handle player death
        if player_hit {
            if let Ok((player_entity, player, _)) = player_query.get_mut(event.entity1) {
                if player.health == 0 {
                    spawn_explosion(&mut commands, &assets, player_entity);
                    audio.play_with_settings(
                        assets.explosion_sound.clone(),
                        PlaybackSettings::ONCE.with_volume(0.5),
                    );
                    commands.entity(player_entity).despawn();
                }
            } else if let Ok((player_entity, player, _)) = player_query.get_mut(event.entity2) {
                if player.health == 0 {
                    spawn_explosion(&mut commands, &assets, player_entity);
                    audio.play_with_settings(
                        assets.explosion_sound.clone(),
                        PlaybackSettings::ONCE.with_volume(0.5),
                    );
                    commands.entity(player_entity).despawn();
                }
            }
        }
    }
}

fn spawn_explosion(commands: &mut Commands, assets: &Res<GameAssets>, entity: Entity) {
    commands.spawn((
        SpriteBundle {
            texture: assets.explosion_texture.clone(),
            transform: Transform::from_translation(Vec3::new(0.0, 0.0, 1.0)),
            ..default()
        },
