<script>
import TaskItem from './components/TaskItem.vue';

export default {
  components: {
    TaskItem
  },
  data() {
    return {
      tasks: [
        { id: 1, title: 'Design UI mockups', status: 'todo' },
        { id: 2, title: 'Implement authentication', status: 'in-progress' },
        { id: 3, title: 'Write documentation', status: 'done' }
      ],
      newTask: '',
      filterStatus: 'all'
    };
  },
  computed: {
    filteredTasks() {
      if (this.filterStatus === 'all') return this.tasks;
      return this.tasks.filter(task => task.status === this.filterStatus);
    }
  },
  methods: {
    addTask() {
      if (this.newTask.trim()) {
        this.tasks.push({
          id: Date.now(),
          title: this.newTask.trim(),
          status: 'todo'
        });
        this.newTask = '';
      }
    },
    updateTask(updatedTask) {
      const index = this.tasks.findIndex(t => t.id === updatedTask.id);
      if (index !== -1) {
        this.tasks.splice(index, 1, updatedTask);
      }
    },
    deleteTask(taskId) {
      this.tasks = this.tasks.filter(task => task.id !== taskId);
    }
  }
};
</script>

