@Configuration
public class ElideConfig {
    @Bean
    public Elide initializeElide(EntityManagerFactory entityManagerFactory) {
        AuditLogger logger = new Slf4jLogger();
        ElideSettingsBuilder builder = new ElideSettingsBuilder(entityManagerFactory)
            .withEntityDictionary(new EntityDictionary(new HashMap<>()))
            .withAuditLogger(logger)
            .withDefaultMaxPageSize(100)
            .withDefaultPageSize(25)
            .withJoinFilterDialect(new RSQLFilterDialect(entityManagerFactory.getMetamodel()))
            .withSubqueryFilterDialect(new RSQLFilterDialect(entityManagerFactory.getMetamodel()));

        return new Elide(builder.build());
